   106→func (s *Service) GetForProvider(ctx context.Context, provider string) (*models.SSOSettings, error) {
   107→	dbSettings, err := s.store.Get(ctx, provider)
   108→	if err != nil && !errors.Is(err, ssosettings.ErrNotFound) {
   109→		return nil, err
   110→	}
   111→
   112→	if dbSettings != nil {
   113→		// Settings are coming from the database thus secrets are encrypted
   114→		dbSettings.Settings, err = s.decryptSecrets(ctx, dbSettings.Settings)
   115→		if err != nil {
   116→			return nil, err
   117→		}
   118→	}
   119→
   120→	systemSettings, err := s.loadSettingsUsingFallbackStrategy(ctx, provider)
   121→	if err != nil {
   122→		return nil, err
   123→	}
   124→
   125→	return s.mergeSSOSettings(dbSettings, systemSettings), nil
   126→}
   127→
   128→func (s *Service) GetForProviderFromCache(ctx context.Context, provider string) (*models.SSOSettings, error) {
   129→	s.cacheMutex.RLock()
   130→	defer s.cacheMutex.RUnlock()
   131→
   132→	for _, setting := range s.cachedSSOSettings {
   133→		if setting.Provider == provider {
   134→			return &models.SSOSettings{
   135→				Provider: setting.Provider,
   136→				Source:   setting.Source,
   137→				Settings: deepCopyMap(setting.Settings),
   138→			}, nil
   139→		}
   140→	}
   141→
   142→	// If settings are not in the cache, we return them from the database if the provider is valid
   143→	if slices.Contains(s.providersList, provider) {
   144→		return s.GetForProvider(ctx, provider)
   145→	}
   146→
   147→	return nil, nil
   148→}
