   150→func (s *Service) GetForProviderWithRedactedSecrets(ctx context.Context, provider string) (*models.SSOSettings, error) {
   151→	if !s.isProviderConfigurable(provider) {
   152→		return nil, ssosettings.ErrNotConfigurable
   153→	}
   154→
   155→	storeSettings, err := s.GetForProvider(ctx, provider)
   156→	if err != nil {
   157→		return nil, err
   158→	}
   159→
   160→	storeSettings.Settings = removeSecrets(storeSettings.Settings)
   161→
   162→	return storeSettings, nil
   163→}
