   467→				}
   468→
   469→				decoded, err := base64.RawStdEncoding.DecodeString(strValue)
   470→				if err != nil {
   471→					s.logger.FromContext(ctx).Error("Failed to decode secret string", "err", err, "value")
   472→					return nil, err
   473→				}
   474→
   475→				decrypted, err := s.secrets.Decrypt(ctx, decoded)
   476→				if err != nil {
