   165→func (s *Service) List(ctx context.Context) ([]*models.SSOSettings, error) {
   166→	result := make([]*models.SSOSettings, 0, len(s.providersList))
   167→	storedSettings, err := s.store.List(ctx)
   168→
   169→	if err != nil {
   170→		return nil, err
   171→	}
   172→
   173→	for _, provider := range s.providersList {
   174→		dbSettings := getSettingByProvider(provider, storedSettings)
   175→		if dbSettings != nil {
   176→			// Settings are coming from the database thus secrets are encrypted
   177→			dbSettings.Settings, err = s.decryptSecrets(ctx, dbSettings.Settings)
   178→			if err != nil {
   179→				return nil, err
   180→			}
   181→		}
   182→		fallbackSettings, err := s.loadSettingsUsingFallbackStrategy(ctx, provider)
   183→		if err != nil {
   184→			return nil, err
   185→		}
   186→
   187→		result = append(result, s.mergeSSOSettings(dbSettings, fallbackSettings))
   188→	}
   189→
   190→	s.setCachedSSOSettings(result)
   191→
   192→	return result, nil
   193→}
