   195→func (s *Service) ListWithRedactedSecrets(ctx context.Context) ([]*models.SSOSettings, error) {
   196→	storeSettings, err := s.List(ctx)
   197→	if err != nil {
   198→		return nil, err
   199→	}
   200→
   201→	configurableSettings := make([]*models.SSOSettings, 0, len(s.configurableProviders))
   202→	for _, provider := range storeSettings {
   203→		if s.isProviderConfigurable(provider.Provider) {
   204→			configurableSettings = append(configurableSettings, provider)
   205→		}
   206→	}
   207→
   208→	for _, storeSetting := range configurableSettings {
   209→		storeSetting.Settings = removeSecrets(storeSetting.Settings)
   210→	}
   211→
   212→	return configurableSettings, nil
   213→}
