   215→func (s *Service) Upsert(ctx context.Context, settings *models.SSOSettings, requester identity.Requester) error {
   216→	if !s.isProviderConfigurable(settings.Provider) {
   217→		return ssosettings.ErrNotConfigurable
   218→	}
   219→
   220→	reloadable, ok := s.reloadables[settings.Provider]
   221→	if !ok {
   222→		return ssosettings.ErrInvalidProvider.Errorf("provider %s not found in reloadables", settings.Provider)
   223→	}
   224→
   225→	storedSettings, err := s.GetForProvider(ctx, settings.Provider)
   226→	if err != nil {
   227→		return err
   228→	}
   229→
   230→	settingsWithSecrets, err := mergeSecrets(settings.Settings, storedSettings.Settings)
   231→	if err != nil {
   232→		return err
   233→	}
   234→	settings.Settings = settingsWithSecrets
   235→
   236→	err = reloadable.Validate(ctx, *settings, *storedSettings, requester)
   237→	if err != nil {
   238→		return err
   239→	}
   240→
   241→	settings.Settings, err = s.encryptSecrets(ctx, settings.Settings)
   242→	if err != nil {
   243→		return err
   244→	}
   245→
   246→	err = s.store.Upsert(ctx, settings)
   247→	if err != nil {
   248→		return err
   249→	}
   250→
   251→	// make a copy of current settings for reload operation and apply overrides
   252→	reloadSettings := *settings
   253→	reloadSettings.Settings = overrideMaps(storedSettings.Settings, settingsWithSecrets)
   254→
   255→	go s.reload(reloadable, settings.Provider, reloadSettings)
   256→
   257→	return nil
   258→}
