   264→func (s *Service) Delete(ctx context.Context, provider string) error {
   265→	if !s.isProviderConfigurable(provider) {
   266→		return ssosettings.ErrNotConfigurable
   267→	}
   268→
   269→	reloadable, ok := s.reloadables[provider]
   270→	if !ok {
   271→		return ssosettings.ErrInvalidProvider.Errorf("provider %s not found in reloadables", provider)
   272→	}
   273→
   274→	err := s.store.Delete(ctx, provider)
   275→	if err != nil {
   276→		return err
   277→	}
   278→
   279→	// When deleting settings for SAML, clear the Settings table
   280→	if provider == social.SAMLProviderName {
   281→		samlSettings := setting.SettingsRemovals{
   282→			"auth.saml": make([]string, 0, len(s.settingsProvider.Current())),
   283→		}
   284→		for k := range s.settingsProvider.Current()["auth.saml"] {
   285→			samlSettings["auth.saml"] = append(samlSettings["auth.saml"], k)
   286→		}
   287→		if err := s.settingsProvider.Update(setting.SettingsBag{}, samlSettings); err != nil {
   288→			s.logger.Warn("Failed to remove SAML settings from the settings table", "error", err)
   289→		}
   290→	}
   291→
   292→	currentSettings, err := s.GetForProvider(ctx, provider)
   293→	if err != nil {
   294→		s.logger.Error("failed to get current settings, skipping reload", "provider", provider, "error", err)
   295→		return nil
   296→	}
   297→
   298→	go s.reload(reloadable, provider, *currentSettings)
   299→
   300→	return nil
   301→}
   302→
   303→func (s *Service) reload(reloadable ssosettings.Reloadable, provider string, currentSettings models.SSOSettings) {
   304→	s.updateCachedSSOSettings(provider, &currentSettings)
   305→
   306→	err := reloadable.Reload(context.Background(), currentSettings)
   307→	if err != nil {
   308→		s.metrics.reloadFailures.WithLabelValues(provider).Inc()
   309→		s.logger.Error("failed to reload the provider", "provider", provider, "error", err)
   310→	}
   311→}
