   317→func (s *Service) RegisterReloadable(provider string, reloadable ssosettings.Reloadable) {
   318→	if s.reloadables == nil {
   319→		s.reloadables = make(map[string]ssosettings.Reloadable)
   320→	}
   321→	s.reloadables[provider] = reloadable
