   324→func (s *Service) RegisterFallbackStrategy(providerRegex string, strategy ssosettings.FallbackStrategy) {
   325→	s.fbStrategies = append(s.fbStrategies, strategy)
   326→}
   327→
   328→func (s *Service) loadSettingsUsingFallbackStrategy(ctx context.Context, provider string) (*models.SSOSettings, error) {
   329→	loadStrategy, ok := s.getFallbackStrategyFor(provider)
   330→	if !ok {
   331→		return nil, errors.New("no fallback strategy found for provider: " + provider)
   332→	}
   333→
   334→	settingsFromSystem, err := loadStrategy.GetProviderConfig(ctx, provider)
   335→	if err != nil {
   336→		return nil, err
   337→	}
   338→
   339→	return &models.SSOSettings{
   340→		Provider: provider,
   341→		Source:   models.System,
   342→		Settings: settingsFromSystem,
   343→	}, nil
   344→}
   345→
   346→func getSettingByProvider(provider string, settings []*models.SSOSettings) *models.SSOSettings {
   347→	for _, item := range settings {
   348→		if item.Provider == provider {
   349→			return item
   350→		}
   351→	}
   352→	return nil
   353→}
   354→
   355→func (s *Service) getFallbackStrategyFor(provider string) (ssosettings.FallbackStrategy, bool) {
   356→	for _, strategy := range s.fbStrategies {
   357→		if strategy.IsMatch(provider) {
   358→			return strategy, true
   359→		}
   360→	}
   361→	return nil, false
   362→}
   363→
   364→func (s *Service) encryptSecrets(ctx context.Context, settings map[string]any) (map[string]any, error) {
   365→	result := deepCopyMap(settings)
   366→	configs := getConfigMaps(result)
   367→
   368→	for _, config := range configs {
   369→		for k, v := range config {
   370→			if IsSecretField(k) && v != "" {
   371→				strValue, ok := v.(string)
   372→				if !ok {
   373→					return result, fmt.Errorf("failed to encrypt %s setting because it is not a string: %v", k, v)
   374→				}
   375→
   376→				encryptedSecret, err := s.secrets.Encrypt(ctx, []byte(strValue), secrets.WithoutScope())
   377→				if err != nil {
   378→					return result, err
   379→				}
   380→				config[k] = base64.RawStdEncoding.EncodeToString(encryptedSecret)
   381→			}
   382→		}
   383→	}
   384→
   385→	return result, nil
   386→}
   387→
   388→func (s *Service) Run(ctx context.Context) error {
   389→	interval := s.cfg.SSOSettingsReloadInterval
   390→	if interval == 0 {
   391→		return nil
   392→	}
   393→
   394→	ticker := time.NewTicker(interval)
   395→
   396→	// start a background process for reloading the SSO settings for all providers at a fixed interval
   397→	// it is useful for high availability setups running multiple Grafana instances
   398→	for {
   399→		select {
   400→		case <-ticker.C:
   401→			s.doReload(ctx)
   402→
   403→		case <-ctx.Done():
   404→			return ctx.Err()
   405→		}
   406→	}
   407→}
   408→
   409→func (s *Service) doReload(ctx context.Context) {
   410→	s.logger.Debug("reloading SSO Settings for all providers")
   411→
   412→	settingsList, err := s.List(ctx)
   413→	if err != nil {
   414→		s.logger.Error("failed to fetch SSO Settings for all providers", "err", err)
   415→		return
   416→	}
   417→
   418→	for provider, connector := range s.reloadables {
   419→		settings := getSettingByProvider(provider, settingsList)
   420→
   421→		if settings == nil || len(settings.Settings) == 0 {
   422→			s.logger.Warn("SSO Settings is empty", "provider", provider)
   423→			continue
   424→		}
   425→
   426→		err = connector.Reload(ctx, *settings)
   427→		if err != nil {
   428→			s.metrics.reloadFailures.WithLabelValues(provider).Inc()
   429→			s.logger.Error("failed to reload SSO Settings", "provider", provider, "err", err)
   430→			continue
   431→		}
   432→	}
   433→}
   434→
   435→// mergeSSOSettings merges the settings from the database with the system settings
   436→// Required because it is possible that the user has configured some of the settings (current Advanced OAuth settings)
   437→// and the rest of the settings have to be loaded from the system settings
   438→func (s *Service) mergeSSOSettings(dbSettings, systemSettings *models.SSOSettings) *models.SSOSettings {
   439→	if dbSettings == nil {
   440→		s.logger.Debug("No SSO Settings found in the database, using system settings")
   441→		return systemSettings
   442→	}
   443→
   444→	s.logger.Debug("Merging SSO Settings", "dbSettings", removeSecrets(dbSettings.Settings), "systemSettings", removeSecrets(systemSettings.Settings))
   445→
   446→	result := &models.SSOSettings{
   447→		Provider: dbSettings.Provider,
   448→		Source:   dbSettings.Source,
   449→		Settings: mergeSettings(dbSettings.Settings, systemSettings.Settings),
   450→		Created:  dbSettings.Created,
   451→		Updated:  dbSettings.Updated,
   452→	}
   453→
   454→	return result
   455→}
   456→
   457→func (s *Service) decryptSecrets(ctx context.Context, settings map[string]any) (map[string]any, error) {
   458→	configs := getConfigMaps(settings)
   459→
   460→	for _, config := range configs {
   461→		for k, v := range config {
   462→			if IsSecretField(k) && v != "" {
   463→				strValue, ok := v.(string)
   464→				if !ok {
   465→					s.logger.FromContext(ctx).Error("Failed to parse secret value, it is not a string", "key", k)
   466→					return nil, fmt.Errorf("secret value is not a string")
   467→				}
   468→
   469→				decoded, err := base64.RawStdEncoding.DecodeString(strValue)
   470→				if err != nil {
   471→					s.logger.FromContext(ctx).Error("Failed to decode secret string", "err", err, "value")
   472→					return nil, err
   473→				}
   474→
   475→				decrypted, err := s.secrets.Decrypt(ctx, decoded)
   476→				if err != nil {
   477→					s.logger.FromContext(ctx).Error("Failed to decrypt secret", "err", err)
   478→					return nil, err
   479→				}
   480→
   481→				config[k] = string(decrypted)
   482→			}
   483→		}
   484→	}
   485→
   486→	return settings, nil
   487→}
   488→
   489→func (s *Service) isProviderConfigurable(provider string) bool {
   490→	enabled, ok := s.configurableProviders[provider]
   491→	return ok && enabled
   492→}
   493→
   494→// removeSecrets removes all the secrets from the map and replaces them with a redacted password
   495→// and returns a new map
   496→func removeSecrets(settings map[string]any) map[string]any {
   497→	result := deepCopyMap(settings)
   498→	configs := getConfigMaps(result)
   499→
   500→	for _, config := range configs {
   501→		for k, v := range config {
   502→			val, ok := v.(string)
   503→			if ok && val != "" && IsSecretField(k) {
   504→				config[k] = setting.RedactedPassword
   505→			}
   506→		}
   507→	}
   508→	return result
   509→}
   510→
   511→// getConfigMaps returns a list of maps that may contain secrets
   512→func getConfigMaps(settings map[string]any) []map[string]any {
   513→	// always include the main settings map
   514→	result := []map[string]any{settings}
   515→
   516→	// for LDAP include settings for each server
   517→	if config, ok := settings["config"].(map[string]any); ok {
   518→		if servers, ok := config["servers"].([]any); ok {
   519→			for _, server := range servers {
   520→				if serverSettings, ok := server.(map[string]any); ok {
   521→					result = append(result, serverSettings)
   522→				}
   523→			}
   524→		}
   525→	}
   526→
   527→	return result
   528→}
   529→
   530→// mergeSettings merges two maps in a way that the values from the first map are preserved
   531→// and the values from the second map are added only if they don't exist in the first map
   532→// or if they contain empty URLs.
   533→func mergeSettings(storedSettings, systemSettings map[string]any) map[string]any {
   534→	settings := make(map[string]any)
   535→
   536→	for k, v := range storedSettings {
   537→		settings[k] = v
   538→	}
   539→
   540→	for k, v := range systemSettings {
   541→		if _, ok := settings[k]; !ok {
   542→			if isMergingAllowed(k) {
   543→				settings[k] = v
   544→			}
   545→		} else if isURL(k) && isEmptyString(settings[k]) {
   546→			// Overwrite all URL settings from the DB containing an empty string with their value
   547→			// from the system settings. This fixes an issue with empty auth_url, api_url and token_url
   548→			// from the DB not being replaced with their values defined in the system settings for
   549→			// the Google provider.
   550→			settings[k] = v
   551→		}
   552→	}
   553→
   554→	return settings
   555→}
   556→
   557→// isMergingAllowed returns true if the field provided can be merged from the system settings.
   558→// It won't allow SAML fields that are part of a group of settings to be merged from system settings
   559→// because the DB settings already contain one valid setting from each group.
   560→func isMergingAllowed(fieldName string) bool {
   561→	forbiddenMergePatterns := []string{"certificate", "private_key", "idp_metadata"}
   562→
   563→	for _, v := range forbiddenMergePatterns {
   564→		if strings.Contains(strings.ToLower(fieldName), strings.ToLower(v)) {
   565→			return false
   566→		}
   567→	}
   568→	return true
   569→}
   570→
   571→// mergeSecrets returns a new map with the current value for secrets that have not been updated
   572→func mergeSecrets(settings map[string]any, storedSettings map[string]any) (map[string]any, error) {
   573→	settingsWithSecrets := deepCopyMap(settings)
   574→	newConfigs := getConfigMaps(settingsWithSecrets)
   575→	storedConfigs := getConfigMaps(storedSettings)
   576→
   577→	for i, config := range newConfigs {
   578→		for k, v := range config {
   579→			if IsSecretField(k) {
   580→				strValue, ok := v.(string)
   581→				if !ok {
   582→					return nil, fmt.Errorf("secret value is not a string")
   583→				}
   584→
   585→				if !isNewSecretValue(strValue) && len(storedConfigs) > i {
   586→					config[k] = storedConfigs[i][k] // use the currently stored value
   587→				}
   588→			}
   589→		}
   590→	}
   591→
   592→	return settingsWithSecrets, nil
   593→}
   594→
   595→func overrideMaps(maps ...map[string]any) map[string]any {
   596→	result := make(map[string]any)
   597→	for _, m := range maps {
   598→		for k, v := range m {
   599→			result[k] = v
   600→		}
   601→	}
   602→	return result
   603→}
   604→
   605→// IsSecretField returns true if the SSO settings field provided is a secret
   606→func IsSecretField(fieldName string) bool {
   607→	secretFieldPatterns := []string{"secret", "private", "certificate", "password", "client_key"}
   608→
   609→	for _, v := range secretFieldPatterns {
   610→		if strings.Contains(strings.ToLower(fieldName), strings.ToLower(v)) {
   611→			return true
   612→		}
   613→	}
   614→	return false
   615→}
   616→
   617→func isURL(fieldName string) bool {
   618→	return strings.HasSuffix(fieldName, "_url")
   619→}
   620→
   621→func isEmptyString(val any) bool {
   622→	_, ok := val.(string)
   623→	return ok && val == ""
   624→}
   625→
   626→func isNewSecretValue(value string) bool {
   627→	return value != setting.RedactedPassword
   628→}
   629→
   630→func deepCopyMap(settings map[string]any) map[string]any {
   631→	newSettings := make(map[string]any)
   632→
   633→	for key, value := range settings {
   634→		switch v := value.(type) {
   635→		case map[string]any:
   636→			newSettings[key] = deepCopyMap(v)
   637→		case []any:
   638→			newSettings[key] = deepCopySlice(v)
   639→		default:
   640→			newSettings[key] = value
   641→		}
   642→	}
   643→
   644→	return newSettings
   645→}
   646→
   647→func deepCopySlice(s []any) []any {
   648→	newSlice := make([]any, len(s))
   649→
   650→	for i, value := range s {
   651→		switch v := value.(type) {
   652→		case map[string]any:
   653→			newSlice[i] = deepCopyMap(v)
   654→		case []any:
   655→			newSlice[i] = deepCopySlice(v)
   656→		default:
   657→			newSlice[i] = value
   658→		}
   659→	}
   660→
   661→	return newSlice
   662→}
   663→
   664→func (s *Service) setCachedSSOSettings(settings []*models.SSOSettings) {
   665→	s.cacheMutex.Lock()
   666→	defer s.cacheMutex.Unlock()
   667→
   668→	s.cachedSSOSettings = settings
   669→}
   670→
   671→func (s *Service) updateCachedSSOSettings(provider string, settings *models.SSOSettings) {
   672→	s.cacheMutex.Lock()
   673→	defer s.cacheMutex.Unlock()
   674→
   675→	for i := range s.cachedSSOSettings {
   676→		if s.cachedSSOSettings[i].Provider == provider {
   677→			s.cachedSSOSettings[i] = settings
   678→			return
   679→		}
   680→	}
   681→
   682→	// Provider not found, append new settings
   683→	s.cachedSSOSettings = append(s.cachedSSOSettings, settings)
   684→}
